/**
 * Handles the unfurling of a URL by extracting metadata such as title, description, image, and favicon.
 * @param {string} url - The URL to unfurl.
 * @returns {Promise<Result<UnfurledData, UnfurlError>>} - A promise that resolves to an object containing the extracted metadata, or null if an error occurs.
 */
export function unfurl(url: string): Promise<Result<UnfurledData, UnfurlError>>;
/**
 * Implements a handler for a GET request where the uri is passed in as a search param called `url`.
 *
 * e.g. GET /foo/bar?url=https://example.com
 *
 * @param {Request} request
 * @returns {Promise<Response>}
 */
export function handleUnfurlRequest(request: Request): Promise<Response>;
export type GoodResult<Value> = {
    /**
     * - The success status.
     */
    ok: true;
    /**
     * - The data extracted from the URL.
     */
    value: Value;
};
export type BadResult<Error> = {
    /**
     * - The success status.
     */
    ok: false;
    /**
     * - The error
     */
    error: Error;
};
export type Result<Value, Error> = GoodResult<Value> | BadResult<Error>;
export type UnfurledData = {
    /**
     * - The title extracted from the URL.
     */
    title?: string | undefined;
    /**
     * - The description extracted from the URL.
     */
    description?: string | undefined;
    /**
     * - The image URL extracted from the URL.
     */
    image?: string | undefined;
    /**
     * - The favicon URL extracted from the URL.
     */
    favicon?: string | undefined;
};
export type UnfurlError = "bad-param" | "failed-fetch";
